const error = $input.first().json;
const workflow = error.workflow?.name || error.workflowName || 'unknown_workflow';
const node = error.execution?.lastNodeExecuted || error.node?.name || 'unknown_node';
const message = error.execution?.error?.message || error.error?.message || JSON.stringify(error).slice(0, 500);
return [{ json: { n8n_execution_id: String(error.execution?.id || $execution.id), workflow_name: workflow, node_name: node, severity: 'error', error_message: message, payload_reference: error.execution?.url || '' } }];
